const qF29Html=`<div style="background:#141414;border:1px solid #2A2A2A;border-radius:10px;padding:14px 18px;margin:12px 0;font-size:13px;line-height:1.7;color:#A3A3A3"><div style="color:#D4D4D4;font-style:italic;margin-bottom:8px">As a hotel owner<br/>I want to reserve all the rooms on a floor before moving to the next floor<br/>So I can maximize the efficiency of the housekeeping staff</div><div style="color:#FACC15;font-weight:600;margin-bottom:4px">Partitions for floor occupancy:</div><div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:12px;font-size:12px"><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">0</span><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">1 – floor full</span><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">overbooked</span></div><div style="color:#D4D4D4;font-weight:600;margin-bottom:4px">Designed test cases:</div><div>1. Test with 1 occupant on the floor</div><div>2. Test with the floor full — ensure next floor is made available</div><div>3. Test with 0 occupants — ensure floor is only available when lower floors are fully booked</div><div>4. Test usability for hotel staff</div><div>5. Test response time at average load with hotel 80% occupied</div></div>`;

